#!/usr/bin/env bash
set -euo pipefail
source "$(dirname "$0")/lib/common.sh"
serial=RFCT90AEEFA; package=org.archphene.linux.pade746c2b5b03d64e570dc2d1e5ee546; activity=org.archphene.linux.kcalc.MainActivity; while (($#)); do case "$1" in --serial) serial="${2:?}"; shift 2;; --package) package="${2:?}"; shift 2;; --activity) activity="${2:?}"; shift 2;; *) archphene_die "unknown argument: $1";; esac; done; archphene_init_adb "$serial"; component="$package/$activity"; wait_log(){ local pattern="$1" deadline=$((SECONDS+12)) log; while ((SECONDS<deadline)); do log="$(archphene_adb_run logcat -d -v brief -s ArchpheneInput ArchpheneRuntime '*:S')"; archphene_regex_contains "$log" "$pattern" && { printf %s "$log"; return; }; sleep .25; done; archphene_die "timed out waiting for log pattern: $pattern"; }
archphene_adb_run shell pm path "$package" >/dev/null; archphene_adb_run logcat -c; archphene_adb_run shell am force-stop "$package"; archphene_adb_run shell am start -W -n "$component" >/dev/null; wait_log 'mapped=true' >/dev/null; archphene_adb_run shell input mouse motionevent MOVE 300 500; archphene_adb_run shell input mouse tap 300 500; archphene_adb_run shell input mouse scroll 300 500 --axis VSCROLL,2 --axis HSCROLL,1; archphene_adb_run shell input touchscreen swipe 200 700 260 730 80; archphene_adb_run shell input keyboard keyevent KEYCODE_A; archphene_adb_run shell input keyboard keycombination -t 120 KEYCODE_SHIFT_LEFT KEYCODE_B; archphene_adb_run shell input keyevent KEYCODE_HOME; sleep .8; archphene_adb_run shell am start -W -n "$component" >/dev/null; sleep .8; archphene_adb_run shell input keyevent KEYCODE_BACK; log="$(wait_log 'Runtime GUI exit=0')"; checks=('mapped=true' 'wl_pointer\] enter:' 'wl_pointer\] button:' 'axis: 0 \(vertical\)' 'axis: 1 \(horizontal\)' 'wl_touch\] down:' 'wl_touch\] motion:' 'wl_touch\] up:' 'wl_keyboard\] key:' 'depressed: 00000001' 'repeat_info: rate: 25 keys/sec; delay: 400 ms' 'wl_keyboard\] leave:' 'xdg_toplevel\] close'); for check in "${checks[@]}"; do archphene_regex_contains "$log" "$check" || archphene_die "missing wev assertion: $check"; done; (( $(grep -c 'wl_keyboard] enter:' <<<"$log") >= 2 )) || archphene_die 'expected keyboard enter on focus and resume'; archphene_note "wev Wayland input passed on $serial"
